void GroupServerApp::KillUserByName(const char* accoutName) {
	Player* l_ply = 0;
	RunChainGetArmor<Player> l(m_plylst);
	for (l_ply = m_plylst.GetNextItem(); l_ply; l_ply = m_plylst.GetNextItem()) {
		if (strcmp(l_ply->m_acctname.c_str(), accoutName) == 0) {
			break;
		}
	}
	if (l_ply) {
		l_ply->EndPlay(nullptr);
		{
			// Notify AccountServer about logout
			WPacket l_wpk = GetWPacket();
			l_wpk.WriteCmd(CMD_PA_USER_LOGOUT);
			l_wpk.WriteLong(l_ply->m_acctid);
			l_wpk.WriteLong(l_ply->m_sessid);
			SendData(m_acctsock, l_wpk);
			
			// Send kick to GateServer
			/*WPacket*/ l_wpk = GetWPacket();
			l_wpk.WriteCmd(CMD_AP_KICKUSER);
			SendToClient(l_ply, l_wpk);
			
			LG("GroupServer", "KillUserByName: killed account [%s]\n", l_ply->m_acctname.c_str());
		}
		// Remove from login list
		m_LoginList.Remove(l_ply->m_acctname);
		// Remove from player list and free
		l_ply->EndRun();
		l_ply->Free();
	} else {
		l.unlock();
	}
}

void GroupServerApp::AP_KICKUSER(DataSocket* datasock, RPacket& pk) {
	Player* l_ply = 0;
	uLong l_acctid = pk.ReadLong();
	RunChainGetArmor<Player> l(m_plylst);
	for (l_ply = m_plylst.GetNextItem(); l_ply; l_ply = m_plylst.GetNextItem()) {
		if (l_ply->m_acctLoginID == l_acctid) {
			break;
		}
	}
	if (l_ply) {
		l_ply->EndPlay(datasock);
		if (l_ply->EndRun()) {
			if (l_ply->m_currcha != -1) {
				// Notify AccountServer about billing end
				WPacket l_wpk = GetWPacket();
				l_wpk.WriteCmd(CMD_PA_USER_BILLEND);
				l_wpk.WriteString(l_ply->m_acctname.c_str());
				SendData(m_acctsock, l_wpk);
			}
			// Notify AccountServer to logout (set status to OFFLINE)
			// This is critical for duplicate login handling - allows new login to proceed
			{
				WPacket l_wpk = GetWPacket();
				l_wpk.WriteCmd(CMD_PA_USER_LOGOUT);
				l_wpk.WriteLong(l_ply->m_acctid);
				l_wpk.WriteLong(l_ply->m_sessid);
				SendData(m_acctsock, l_wpk);
			}
			// Notify GateServer to disconnect the client
			WPacket l_wpk = GetWPacket();
			l_wpk.WriteCmd(CMD_AP_KICKUSER);
			SendToClient(l_ply, l_wpk);
			LG("GroupServer", "kicked acctid/acctname:[%d]/[%s] due to duplicate login\n", l_ply->m_acctid, l_ply->m_acctname.c_str());
		}
		m_LoginList.Remove(l_ply->m_acctname);
		l_ply->Free();
	} else {
		l.unlock();
		// Player not found - likely stale session after server restart
		// Still notify AccountServer to clear the account status so new login can proceed
		LG("GroupServer", "recieved kick acctid:[%d] command (not in play list) - clearing stale session\n", l_acctid);
		WPacket l_wpk = GetWPacket();
		l_wpk.WriteCmd(CMD_PA_USER_LOGOUT);
		l_wpk.WriteLong(l_acctid);  // Use the acctLoginID from kick command
		l_wpk.WriteLong(0);         // Session ID unknown, but logout should still work
		SendData(m_acctsock, l_wpk);
	}
}

