	int nHairTestCnt[4] = {2000, 2062, 2124, 2291};
	int nFaceTestCnt[4] = {2554, 2554, 2554, 2554};
	int nSelHairNum[4] = {8, 8, 8, 4};
	int nSelFaceNum[4] = {8, 8, 8, 8};

	int index = typeID - 1;
