void GroupServerApp::MP_MUTE_PLAYER(Player* player, DataSocket* datasock, RPacket& pk) {
	const auto name = pk.ReadString();
	const auto time = pk.ReadLong();
	time > 0 ? player->EstopPlayer(name, time)
			 : player->DelEstopPlayer(name);
}
